package org.apache.commons.math3.optimization.univariate.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.analysis.UnivariateFunction;
import org.apache.commons.math3.analysis.FunctionUtils;
import org.apache.commons.math3.analysis.function.Sin;
import org.apache.commons.math3.analysis.function.StepFunction;
import org.apache.commons.math3.optimization.GoalType;
import org.apache.commons.math3.optimization.univariate.BrentOptimizer;
import org.apache.commons.math3.optimization.univariate.UnivariatePointValuePair;

import static org.junit.Assert.assertTrue;

public class StepDefs {
    private BrentOptimizer optimizer;
    private UnivariateFunction function;
    private double minPoint;
    private double maxPoint;
    private UnivariatePointValuePair result;
    private double expectedBestPoint;

    @Given("a BrentOptimizer with relative threshold {double} and absolute threshold {double}")
    public void a_brent_optimizer_with_relative_threshold_and_absolute_threshold(Double relThreshold, Double absThreshold) {
        optimizer = new BrentOptimizer(relThreshold, absThreshold);
    }

    @Given("a target function f\\(x\\) = Sin\\(x\\) + StepFunction\\(x\\)")
    public void a_target_function_with_step_function(io.cucumber.datatable.DataTable stepData) {
        Sin sinFunction = new Sin();

        // Extract step function data from the table
        java.util.List<java.util.Map<String, String>> rows = stepData.asMaps();
        double[] stepLocations = new double[rows.size()];
        double[] stepValues = new double[rows.size()];

        for (int i = 0; i < rows.size(); i++) {
            stepLocations[i] = Double.parseDouble(rows.get(i).get("step_location"));
            stepValues[i] = Double.parseDouble(rows.get(i).get("step_value"));
        }

        StepFunction stepFunction = new StepFunction(stepLocations, stepValues);
        function = FunctionUtils.add(sinFunction, stepFunction);
    }

    @When("I minimize the function in the interval \\[{double}, {double}\\]")
    public void i_minimize_the_function_in_the_interval(Double min, Double max) {
        try {
            result = optimizer.optimize(200, function, GoalType.MINIMIZE, min, max);
        } catch (Exception e) {
            // Handle any exceptions during optimization
            throw new RuntimeException("Optimization failed: " + e.getMessage(), e);
        }
    }

    @Then("the returned point should have a function value less than or equal to the value at expected best point {double}")
    public void the_returned_point_should_have_a_function_value_less_than_or_equal_to_the_value_at_expected_best_point(Double expectedBestPoint) {
        double resultValue = result.getValue();
        double expectedValue = function.value(expectedBestPoint);

        // According to the bug, the optimizer currently doesn't return the best point found
        // So this test should fail with the buggy implementation
        assertTrue("Best point not reported: result value = " + resultValue + 
                  ", expected value = " + expectedValue, resultValue <= expectedValue);
    }
}

